-- Dev setup: TBZ organization under the seeded root organization, plus two
-- external sub-organizations (Extern A, Extern B) under TBZ to exercise
-- resource scoping across the org hierarchy.
-- User memberships and role assignments live in 99_demo_data.sql next to the
-- user_profiles rows they reference.

INSERT INTO organizations (id, parent_id, name) VALUES
  ('01980000-0000-7000-8000-000000000002', '01980000-0000-7000-8000-000000000001', 'TBZ'),
  ('01980000-0000-7000-8000-000000000003', '01980000-0000-7000-8000-000000000002', 'Extern A'),
  ('01980000-0000-7000-8000-000000000004', '01980000-0000-7000-8000-000000000002', 'Extern B');

-- Raw INSERT bypasses OrganizationService, so the template copies the service
-- would create must be seeded too (an org must never exist without its
-- default roles). Same pattern as the root copies in the RBAC migration.
INSERT INTO roles (id, organization_id, name, description, permissions)
SELECT m.copy_id::uuid, m.org_id::uuid, t.name, t.description, t.permissions
FROM roles t
JOIN (VALUES
    -- TBZ copies (c1..c5)
    ('01980000-0000-7000-8000-0000000000a1', '01980000-0000-7000-8000-0000000000c1', '01980000-0000-7000-8000-000000000002'),
    ('01980000-0000-7000-8000-0000000000a2', '01980000-0000-7000-8000-0000000000c2', '01980000-0000-7000-8000-000000000002'),
    ('01980000-0000-7000-8000-0000000000a3', '01980000-0000-7000-8000-0000000000c3', '01980000-0000-7000-8000-000000000002'),
    ('01980000-0000-7000-8000-0000000000a4', '01980000-0000-7000-8000-0000000000c4', '01980000-0000-7000-8000-000000000002'),
    ('01980000-0000-7000-8000-0000000000a5', '01980000-0000-7000-8000-0000000000c5', '01980000-0000-7000-8000-000000000002'),
    -- Extern A copies (d1..d5)
    ('01980000-0000-7000-8000-0000000000a1', '01980000-0000-7000-8000-0000000000d1', '01980000-0000-7000-8000-000000000003'),
    ('01980000-0000-7000-8000-0000000000a2', '01980000-0000-7000-8000-0000000000d2', '01980000-0000-7000-8000-000000000003'),
    ('01980000-0000-7000-8000-0000000000a3', '01980000-0000-7000-8000-0000000000d3', '01980000-0000-7000-8000-000000000003'),
    ('01980000-0000-7000-8000-0000000000a4', '01980000-0000-7000-8000-0000000000d4', '01980000-0000-7000-8000-000000000003'),
    ('01980000-0000-7000-8000-0000000000a5', '01980000-0000-7000-8000-0000000000d5', '01980000-0000-7000-8000-000000000003'),
    -- Extern B copies (e1..e5)
    ('01980000-0000-7000-8000-0000000000a1', '01980000-0000-7000-8000-0000000000e1', '01980000-0000-7000-8000-000000000004'),
    ('01980000-0000-7000-8000-0000000000a2', '01980000-0000-7000-8000-0000000000e2', '01980000-0000-7000-8000-000000000004'),
    ('01980000-0000-7000-8000-0000000000a3', '01980000-0000-7000-8000-0000000000e3', '01980000-0000-7000-8000-000000000004'),
    ('01980000-0000-7000-8000-0000000000a4', '01980000-0000-7000-8000-0000000000e4', '01980000-0000-7000-8000-000000000004'),
    ('01980000-0000-7000-8000-0000000000a5', '01980000-0000-7000-8000-0000000000e5', '01980000-0000-7000-8000-000000000004')
) AS m(template_id, copy_id, org_id) ON t.id = m.template_id::uuid;
